/* eslint-disable fp/no-let, fp/no-mutation, fp/no-mutating-methods --
   a real-time cellular-automaton game loop is inherently imperative (per-step
   grid, entity and particle mutation, double-buffered Game-of-Life pass); the
   project's functional-purity rules don't fit and immutable rebuilds every tick
   would be slower and far less readable. Scope: this one game component. */
import React, {useEffect, useRef, useState} from 'react'
import {golStep} from './life'

// Coarse pixel grid, rendered as chunky cells. Landscape so it stays short on the
// page. Canvas size is fixed and reserved up front → no CLS (cls.spec.ts stays green).
const COLS = 80
const ROWS = 44
const CELL = 6
const W = COLS * CELL
const H = ROWS * CELL
const STEP_MS = 65 // sim tick; deliberately chunky for a retro cellular look
const FIRE_EVERY = 2 // auto-fire a laser every N ticks
const SPAWN_EVERY = 13 // spawn a UFO every N ticks
const UFO_MOVE_EVERY = 3 // UFOs descend one cell every N ticks
const PER_KILL = 4 // points per UFO destroyed
// Hit this score and you "reach 404": the score freezes, your guns die (bullets
// cleared, no more firing) and an endless swarm floods in — impossible to survive.
// Reaching 404 IS the doom, not a win. 404 points = 101 kills × 4.
const DOOM_SCORE = 404
const HI_KEY = 'lifeshooter_hi'

// 5×5 ship sprite; gun fires from the apex (col 2, row 0).
const SHIP: [number, number][] = [
  [2, 0],
  [1, 1], [2, 1], [3, 1],
  [0, 2], [1, 2], [2, 2], [3, 2], [4, 2],
  [0, 3], [2, 3], [4, 3],
  [0, 4], [4, 4],
]
// 5×3 saucer sprite.
const UFO: [number, number][] = [
  [1, 0], [2, 0], [3, 0],
  [0, 1], [1, 1], [2, 1], [3, 1], [4, 1],
  [1, 2], [3, 2],
]

type Ufo = {x: number; y: number}
type Laser = {x: number; y: number}
type Phase = 'idle' | 'playing' | 'over'
type EndCause = 'fire' | 'swarm'

const clamp = (n: number, lo: number, hi: number) => Math.max(lo, Math.min(hi, n))

// High score is best-effort: storage-blocked browsers (private mode, cookies/
// storage disabled) throw on access. Reads fall back to 0, writes are swallowed,
// so a blocked store degrades to an in-memory high score instead of crashing the
// rAF loop mid-game.
const readHi = (): number => {
  try {
    return Number(window.localStorage.getItem(HI_KEY) ?? 0)
  } catch {
    return 0
  }
}
const writeHi = (v: number): void => {
  try {
    window.localStorage.setItem(HI_KEY, String(v))
  } catch {
    /* storage blocked — high score is best-effort */
  }
}

export const LifeShooter = () => {
  const canvasRef = useRef<HTMLCanvasElement | null>(null)
  const genRef = useRef(0) // identifies the current run; stale loops bail on mismatch
  const [phase, setPhase] = useState<Phase>('idle')
  const [run, setRun] = useState(0) // bumping this (re)starts the loop
  const [score, setScore] = useState(0)
  const [hi, setHi] = useState(0)
  const [cause, setCause] = useState<EndCause>('fire') // how the last run ended

  useEffect(() => {
    setHi(readHi())
  }, [])

  useEffect(() => {
    if (run === 0) return undefined
    const canvas = canvasRef.current
    const ctx = canvas?.getContext('2d')
    if (!canvas || !ctx) return undefined

    // This run's generation. The game-over animation keeps the loop alive, so a
    // previous run's rAF chain could otherwise survive into the next game and draw
    // over it — any loop whose gen no longer matches the latest run bails out.
    const gen = run
    genRef.current = gen
    let stopped = false

    // Honor prefers-reduced-motion like the rest of the site (CSS handles the
    // static decorations; this canvas game is JS-driven so it must gate itself).
    // When set, render the fire and the swarm banner in steady colors instead of
    // the per-tick >3 Hz color flip — that flashing is a photosensitivity/seizure
    // risk (WCAG 2.3.1). Gameplay motion (ship/UFO positions) stays.
    const reduce = window.matchMedia?.('(prefers-reduced-motion: reduce)').matches ?? false

    // --- world state (mutable, local to this run) ---
    let fire: Uint8Array = new Uint8Array(COLS * ROWS) // Game-of-Life "fire" layer (current)
    let sx = (COLS >> 1) - 2
    let sy = ROWS - 6
    const keys = {l: false, r: false, u: false, d: false}
    let touch: {x: number; y: number} | null = null // drag target in grid coords
    const ufos: Ufo[] = []
    const lasers: Laser[] = []
    let pts = 0
    let dead = false
    let invasion = false // reached the cap → defenceless, endless swarm
    let tick = 0
    let spawnAcc = 0
    let acc = 0
    let lastT = performance.now()
    let raf = 0

    const idx = (x: number, y: number) => y * COLS + x
    const inb = (x: number, y: number) => x >= 0 && x < COLS && y >= 0 && y < ROWS
    const shipCells = (): [number, number][] => SHIP.map(([dx, dy]) => [sx + dx, sy + dy])
    const ufoCells = (u: Ufo): [number, number][] => UFO.map(([dx, dy]) => [u.x + dx, u.y + dy])

    const spawnWave = (n: number) => {
      for (let k = 0; k < n && ufos.length < 90; k++)
        ufos.push({x: 1 + Math.floor(Math.random() * (COLS - 6)), y: Math.floor(Math.random() * 8)})
    }

    // Reaching the cap doesn't win — it dooms you: score freezes, guns go dead,
    // and a relentless swarm pours in. You can only dodge until something burns you.
    const enterInvasion = () => {
      invasion = true
      lasers.length = 0 // guns dead — no more bullets, so the score can't climb
      spawnWave(16) // the sky fills at once
    }

    const igniteUfo = (u: Ufo) => {
      for (const [x, y] of ufoCells(u)) if (inb(x, y)) fire[idx(x, y)] = 1
      const i = ufos.indexOf(u)
      if (i >= 0) ufos.splice(i, 1)
      if (!dead && !invasion) {
        pts = Math.min(pts + PER_KILL, DOOM_SCORE)
        if (pts >= DOOM_SCORE) enterInvasion()
      }
    }

    const onKey = (down: boolean) => (e: KeyboardEvent) => {
      let hit = true
      if (e.key === 'ArrowLeft') keys.l = down
      else if (e.key === 'ArrowRight') keys.r = down
      else if (e.key === 'ArrowUp') keys.u = down
      else if (e.key === 'ArrowDown') keys.d = down
      else hit = false
      if (hit) e.preventDefault() // arrows shouldn't scroll the page while playing
    }
    const kd = onKey(true)
    const ku = onKey(false)
    window.addEventListener('keydown', kd)
    window.addEventListener('keyup', ku)

    // Drag steering — the only way to play on touch devices (no arrow keys). Tracks
    // the pointer while pressed and maps it to grid coords; the ship eases toward it.
    const ptMove = (e: PointerEvent) => {
      const rect = canvas.getBoundingClientRect()
      touch = {
        x: ((e.clientX - rect.left) / rect.width) * COLS,
        y: ((e.clientY - rect.top) / rect.height) * ROWS,
      }
    }
    const ptDown = (e: PointerEvent) => {
      canvas.setPointerCapture(e.pointerId)
      ptMove(e)
    }
    const ptDrag = (e: PointerEvent) => {
      if (touch) ptMove(e)
    }
    const ptUp = () => {
      touch = null
    }
    canvas.addEventListener('pointerdown', ptDown)
    canvas.addEventListener('pointermove', ptDrag)
    canvas.addEventListener('pointerup', ptUp)
    canvas.addEventListener('pointercancel', ptUp)

    const step = () => {
      tick += 1

      if (!dead) {
        if (touch) {
          // Ease toward the finger (centre the 5-wide ship on it), max 2 cells/step.
          sx += clamp(touch.x - 2 - sx, -2, 2)
          sy += clamp(touch.y - 2 - sy, -2, 2)
        } else {
          if (keys.l) sx -= 1
          if (keys.r) sx += 1
          if (keys.u) sy -= 1
          if (keys.d) sy += 1
        }
        sx = clamp(sx, 0, COLS - 5)
        sy = clamp(sy, ROWS >> 1, ROWS - 5) // stay in the lower half
        // Guns die once the swarm arrives — you can still dodge, but not shoot.
        if (!invasion && tick % FIRE_EVERY === 0) lasers.push({x: sx + 2, y: sy - 1})
      }

      // Lasers fly up; a hit seeds fire on the laser cell AND the whole UFO.
      for (let li = lasers.length - 1; li >= 0; li--) {
        const L = lasers[li]
        // The shot that reaches the cap triggers enterInvasion(), which clears all
        // lasers mid-loop — bail out rather than deref a now-empty slot.
        if (!L) break
        L.y -= 1
        const struck = ufos.find((u) => ufoCells(u).some(([x, y]) => x === L.x && y === L.y))
        if (struck) {
          if (inb(L.x, L.y)) fire[idx(L.x, L.y)] = 1
          igniteUfo(struck)
          lasers.splice(li, 1)
        } else if (L.y < 0) {
          lasers.splice(li, 1)
        }
      }

      if (!dead) {
        if (invasion) {
          spawnWave(2) // the swarm never stops
        } else {
          spawnAcc += 1
          if (spawnAcc >= SPAWN_EVERY) {
            spawnAcc = 0
            ufos.push({x: 1 + Math.floor(Math.random() * (COLS - 6)), y: 0})
          }
        }
        if (tick % UFO_MOVE_EVERY === 0) {
          for (let ui = ufos.length - 1; ui >= 0; ui--) {
            const u = ufos[ui]!
            u.y += 1
            if (u.y > ROWS) ufos.splice(ui, 1)
            // Flying into the ship ignites the UFO (then its fire ends you).
            else if (!dead && ufoCells(u).some(([x, y]) => shipCells().some(([px, py]) => px === x && py === y)))
              igniteUfo(u)
          }
        }
      }

      // Evolve the fire layer one Game-of-Life generation (B3/S23). golStep is a
      // pure, unit-tested function (see life.ts / life.test.ts); closures read the
      // `fire` binding, so they see the new grid after reassignment.
      fire = golStep(fire, COLS, ROWS)

      // Fire spreading into a UFO ignites it (chain reaction via gliders etc.).
      for (let ui = ufos.length - 1; ui >= 0; ui--) {
        const u = ufos[ui]!
        if (ufoCells(u).some(([x, y]) => inb(x, y) && fire[idx(x, y)])) igniteUfo(u)
      }
      // Fire reaching the ship: game over — but the simulation keeps burning.
      if (!dead && shipCells().some(([x, y]) => inb(x, y) && fire[idx(x, y)])) {
        dead = true
        for (const [x, y] of shipCells()) if (inb(x, y)) fire[idx(x, y)] = 1
        const best = Math.max(pts, readHi())
        writeHi(best)
        setHi(best)
        setScore(pts)
        setCause(invasion ? 'swarm' : 'fire')
        setPhase('over')
      }
    }

    const draw = () => {
      ctx.fillStyle = '#0e0e0e'
      ctx.fillRect(0, 0, W, H)
      // fire layer (flickers warm)
      for (let y = 0; y < ROWS; y++)
        for (let x = 0; x < COLS; x++)
          if (fire[idx(x, y)]) {
            ctx.fillStyle = reduce ? '#ff5a00' : (x + y + tick) & 1 ? '#ffcc00' : '#ff5a00'
            ctx.fillRect(x * CELL, y * CELL, CELL, CELL)
          }
      // UFOs
      ctx.fillStyle = '#6cf'
      for (const u of ufos) for (const [x, y] of ufoCells(u)) ctx.fillRect(x * CELL, y * CELL, CELL, CELL)
      // lasers
      ctx.fillStyle = '#fff'
      for (const L of lasers) if (inb(L.x, L.y)) ctx.fillRect(L.x * CELL, L.y * CELL, CELL, CELL)
      // ship (unless burnt)
      if (!dead) {
        ctx.fillStyle = '#ff0'
        for (const [x, y] of shipCells()) ctx.fillRect(x * CELL, y * CELL, CELL, CELL)
      }
      // HUD
      ctx.font = "13px 'DM Mono', ui-monospace, monospace"
      ctx.fillStyle = '#ff0'
      ctx.textAlign = 'left'
      ctx.fillText(`SCORE ${String(pts).padStart(4, '0')} / ${String(DOOM_SCORE).padStart(4, '0')}`, 6, 16)
      // Doomed-state banner: you reached the cap; the swarm is inbound.
      if (invasion && !dead) {
        ctx.fillStyle = reduce ? '#ff3b2f' : tick & 2 ? '#ff3b2f' : '#ffcc00'
        ctx.textAlign = 'center'
        ctx.fillText('★ 404 · THE SWARM ★', W / 2, 16)
      }
    }

    const loop = (now: number) => {
      if (stopped || genRef.current !== gen) return // superseded by a newer run
      acc += now - lastT
      lastT = now
      let guard = 0
      while (acc >= STEP_MS && guard < 5) {
        step()
        acc -= STEP_MS
        guard++
      }
      draw()
      raf = requestAnimationFrame(loop)
    }
    raf = requestAnimationFrame(loop)

    return () => {
      stopped = true
      cancelAnimationFrame(raf)
      window.removeEventListener('keydown', kd)
      window.removeEventListener('keyup', ku)
      canvas.removeEventListener('pointerdown', ptDown)
      canvas.removeEventListener('pointermove', ptDrag)
      canvas.removeEventListener('pointerup', ptUp)
      canvas.removeEventListener('pointercancel', ptUp)
    }
  }, [run])

  const start = () => {
    setScore(0)
    setPhase('playing')
    setRun((r) => r + 1)
  }

  return (
    <div className="life-shooter">
      <div className="life-shooter-stage" style={{width: W, maxWidth: '100%', aspectRatio: `${W} / ${H}`}}>
        <canvas
          ref={canvasRef}
          width={W}
          height={H}
          tabIndex={0}
          role="img"
          aria-label="UFO shooter: arrow keys fly your ship, lasers fire automatically; destroyed UFOs ignite and burn via Conway's Game of Life."
        />
        {phase !== 'playing' ? (
          <div className="life-shooter-overlay mono">
            {phase === 'over' && cause === 'swarm' ? (
              <p className="mb-3">
                ★ YOU REACHED 404 ★
                <br />
                the swarm consumed you · <span className="score-num">{String(score).padStart(4, '0')}</span>
              </p>
            ) : phase === 'over' ? (
              <p className="mb-3">
                GAME OVER
                <br />
                score <span className="score-num">{String(score).padStart(4, '0')}</span> · high{' '}
                {String(hi).padStart(4, '0')}
              </p>
            ) : (
              <p className="mb-3">
                UFO DEFENSE
                <br />
                how close to {String(DOOM_SCORE).padStart(4, '0')} dare you get?
              </p>
            )}
            <button type="button" className="life-shooter-btn yellow" onClick={start}>
              {phase === 'idle' ? '▶ PLAY' : '▶ PLAY AGAIN'}
            </button>
          </div>
        ) : null}
      </div>
    </div>
  )
}
