/* eslint-disable fp/no-let, fp/no-mutation --
   a cellular-automaton step is inherently a tight imperative grid loop; an
   immutable rebuild per cell would be slower and less readable. Pure at the
   boundary: it never mutates its input and returns a fresh grid. */

// Conway's Game of Life step (B3/S23) on a flat row-major grid, with NO wrap-around
// at the borders (edge cells simply have fewer neighbours). Returns a new grid and
// leaves `cur` untouched. This is the "fire" layer's evolution in the 404
// mini-game (LifeShooter) — kept standalone so the rule is unit-testable.
export function golStep(cur: Uint8Array, cols: number, rows: number): Uint8Array {
  const next = new Uint8Array(cols * rows)
  for (let y = 0; y < rows; y++) {
    for (let x = 0; x < cols; x++) {
      let n = 0
      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          if (dx === 0 && dy === 0) continue
          const nx = x + dx
          const ny = y + dy
          if (nx >= 0 && nx < cols && ny >= 0 && ny < rows && cur[ny * cols + nx]) n++
        }
      }
      const i = y * cols + x
      next[i] = (cur[i] ? n === 2 || n === 3 : n === 3) ? 1 : 0
    }
  }
  return next
}
